import Container from "../Container";
import FundsTabs from "./FundsTabs";

export default function Funds() {
  return (
    <section className="my-14">
      <Container>
        <p className="text-[#5B6469] max-w-3xl mb-6">
          At Damroo Components, we provide a comprehensive range of sheet metal
          manufacturing and industrial job work services tailored to meet the
          diverse needs of industries. Our facility operates under a
          quality-driven system certified with ISO 9001:2015, ensuring
          consistent manufacturing standards, process control, and customer
          satisfaction.
        </p>
        <FundsTabs />
      </Container>
    </section>
  );
}
